mapper.select:
SELECT sppc.*,spp.id as purchase_id,spp.package_name,smpd.email_content,smpd.email_title,smpd.send_email FROM store_package_purchase_consume sppc LEFT JOIN store_email_package_purchase spp ON spp.id=sppc.email_package_id LEFT JOIN store_message_push_detail smpd ON smpd.id=sppc.push_detail_id WHERE 1=1
and spp.package_name like CONCAT(CONCAT('%',#{storePackagePurchaseConsumeModel.packageName}),'%')
and sppc.seller_id = #{storePackagePurchaseConsumeModel.sellerId}
